const express = require('express');
const fs = require('fs');
const xml2js = require('xml2js');
const XmlDomParser = require('xmldom').XMLParser;
const XmlDomSerializer = require('xmldom').XMLSerializer;
const app = express();
const port = 3000;

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

app.post('/upload', (req, res) => {
  const parser = new XmlDomParser();
  const serializer = new XmlDomSerializer();

  let xmlData = req.body;

  // Limit the number of characters to prevent XXE attacks
  if (xmlData.length > 1048576) {
    return res.status(413).send('Request entity too large');
  }

  parser.parseString(xmlData, (err, xmlDoc) => {
    if (err) {
      return res.status(500).send('Error parsing XML');
    }

    // Disable DTD processing to prevent XXE attacks
    xmlDoc.doctype = null;

    const jsonObject = new xml2js.Parser().parseString(serializer.serializeToString(xmlDoc));

    res.json(jsonObject);
  });
});

app.listen(port, () => {
  console.log(`Server is running on port ${port}`);
});